 1→import { z } from "zod";
 2→import { ENTITY_CATEGORIES, ENTITY_PRIORITIES } from "../../shared/contracts";
 3→
 4→// Azure structured output requires all properties in `required` — no optional fields allowed.
 5→// Use "none" sentinel in the extraction schema, then strip it to undefined after parsing.
 6→const extractionCategorySchema = z.enum([...ENTITY_CATEGORIES, "none"]).transform(
 7→  (v) => (v === "none" ? undefined : v),
 8→);
 9→
10→const extractionPrioritySchema = z.enum([...ENTITY_PRIORITIES, "none"]).transform(
11→  (v) => (v === "none" ? undefined : v),
12→);
13→
14→const extractionEntityBaseSchema = z.object({
15→  tempId: z.string().min(1),
16→  kind: z.enum(["project", "feature", "task", "decision", "question"]),
17→  text: z.string().min(3).max(200),
18→  confidence: z.number().min(0).max(1),
19→  evidence: z.string().min(1),
20→  category: extractionCategorySchema,
21→  priority: extractionPrioritySchema,
22→}).strict();
23→
24→const extractionEntityWithAssigneeSchema = extractionEntityBaseSchema.extend({
25→  assignee_name: z.string().min(1),
26→}).strict();
27→
28→const extractionEntityWithResolvedFromSchema = extractionEntityBaseSchema.extend({
29→  resolvedFromMessageId: z.string().min(1),
30→}).strict();
31→
32→const extractionEntityWithAssigneeAndResolvedFromSchema = extractionEntityBaseSchema.extend({
33→  assignee_name: z.string().min(1),
34→  resolvedFromMessageId: z.string().min(1),
35→}).strict();
36→
37→const extractionEntitySchema = z.union([
38→  extractionEntityBaseSchema,
39→  extractionEntityWithAssigneeSchema,
40→  extractionEntityWithResolvedFromSchema,
41→  extractionEntityWithAssigneeAndResolvedFromSchema,
42→]);
43→
44→export const extractionRelationshipSchema = z.object({
45→  kind: z.string().min(1),
46→  fromTempId: z.string().min(1),
47→  toTempId: z.string().min(1),
48→  confidence: z.number().min(0).max(1),
49→  fromText: z.string().min(1),
50→  toText: z.string().min(1),
51→}).strict();
52→
53→export const extractionResultSchema = z.object({
54→  entities: z.array(extractionEntitySchema),
55→  relationships: z.array(extractionRelationshipSchema),
56→  tools: z.array(z.string().min(1)),
57→}).strict();
58→
59→export type ExtractionPromptEntity = z.infer<typeof extractionEntitySchema>;
60→export type ExtractionPromptRelationship = z.infer<typeof extractionRelationshipSchema>;
61→export type ExtractionPromptOutput = z.infer<typeof extractionResultSchema>;
62→
63→export function parseExtractionOutput(payload: unknown):
64→  | { ok: true; data: ExtractionPromptOutput }
65→  | { ok: false; error: string } {
66→  const result = extractionResultSchema.safeParse(payload);
67→  if (result.success) {
68→    return { ok: true, data: result.data };
69→  }
70→
71→  return {
72→    ok: false,
73→    error: result.error.issues[0]?.message ?? "Invalid extraction payload",
74→  };
75→}
76→

  1→import { describe, expect, it } from "bun:test";
  2→import { randomUUID } from "node:crypto";
  3→import { RecordId } from "surrealdb";
  4→import { collectSseEvents, fetchJson, setupSmokeSuite } from "./smoke-test-kit";
  5→
  6→type ChatMessageResponse = {
  7→  messageId: string;
  8→  userMessageId: string;
  9→  conversationId: string;
 10→  workspaceId: string;
 11→  streamUrl: string;
 12→};
 13→
 14→type StreamEvent =
 15→  | { type: "assistant_message"; messageId: string; text: string }
 16→  | {
 17→      type: "extraction";
 18→      messageId: string;
 19→      entities: Array<{ id: string; kind: string; text: string; confidence: number }>;
 20→    }
 21→  | { type: "done"; messageId: string }
 22→  | { type: "error"; messageId: string; error: string }
 23→  | { type: string; messageId: string };
 24→
 25→const getRuntime = setupSmokeSuite("priority");
 26→
 27→describe("priority extraction smoke", () => {
 28→  let workspace: { workspaceId: string; conversationId: string };
 29→
 30→  it("extracts high or critical priority from urgent task message", async () => {
 31→    const { baseUrl, surreal } = getRuntime();
 32→
 33→    workspace = await fetchJson<{ workspaceId: string; conversationId: string }>(`${baseUrl}/api/workspaces`, {
 34→      method: "POST",
 35→      headers: { "Content-Type": "application/json" },
 36→      body: JSON.stringify({
 37→        name: `Priority Smoke ${Date.now()}`,
 38→        ownerDisplayName: "Marcus",
 39→      }),
 40→    });
 41→
 42→    const message = await fetchJson<ChatMessageResponse>(`${baseUrl}/api/chat/messages`, {
 43→      method: "POST",
 44→      headers: { "Content-Type": "application/json" },
 45→      body: JSON.stringify({
 46→        clientMessageId: randomUUID(),
 47→        workspaceId: workspace.workspaceId,
 48→        conversationId: workspace.conversationId,
 49→        text: "We urgently need to fix the login bug ASAP",
 50→      }),
 51→    });
 52→
 53→    const events = await collectSseEvents<StreamEvent>(`${baseUrl}${message.streamUrl}`, 15_000);
 54→    const extractionEvent = events.find((event) => event.type === "extraction");
 55→    expect(extractionEvent).toBeDefined();
 56→
 57→    if (!extractionEvent || extractionEvent.type !== "extraction") {
 58→      throw new Error("Expected extraction event in SSE stream");
 59→    }
 60→
 61→    const taskEntity = extractionEvent.entities.find((entity) => entity.kind === "task");
 62→    expect(taskEntity).toBeDefined();
 63→
 64→    const userMessageRecord = new RecordId("message", message.userMessageId);
 65→    const [taskRows] = await surreal
 66→      .query<[Array<{ id: RecordId<"task", string>; title: string; priority?: string }>]>(
 67→        "SELECT id, title, priority FROM task WHERE source_message = $sourceMessage;",
 68→        { sourceMessage: userMessageRecord },
 69→      )
 70→      .collect<[Array<{ id: RecordId<"task", string>; title: string; priority?: string }>]>();
 71→
 72→    expect(taskRows.length).toBeGreaterThan(0);
 73→    const task = taskRows[0];
 74→    if (!task) {
 75→      throw new Error("Task record was not persisted");
 76→    }
 77→
 78→    expect(task.priority).toBeDefined();
 79→    expect(["high", "critical"]).toContain(task.priority);
 80→  }, 30_000);
 81→
 82→  it("defaults to medium priority when no urgency signal", async () => {
 83→    const { baseUrl, surreal } = getRuntime();
 84→
 85→    const message = await fetchJson<ChatMessageResponse>(`${baseUrl}/api/chat/messages`, {
 86→      method: "POST",
 87→      headers: { "Content-Type": "application/json" },
 88→      body: JSON.stringify({
 89→        clientMessageId: randomUUID(),
 90→        workspaceId: workspace.workspaceId,
 91→        conversationId: workspace.conversationId,
 92→        text: "We should implement dark mode for the settings page",
 93→      }),
 94→    });
 95→
 96→    const events = await collectSseEvents<StreamEvent>(`${baseUrl}${message.streamUrl}`, 15_000);
 97→    const extractionEvent = events.find((event) => event.type === "extraction");
 98→    expect(extractionEvent).toBeDefined();
 99→
100→    const userMessageRecord = new RecordId("message", message.userMessageId);
101→    const [taskRows] = await surreal
102→      .query<[Array<{ id: RecordId<"task", string>; title: string; priority?: string }>]>(
103→        "SELECT id, title, priority FROM task WHERE source_message = $sourceMessage;",
104→        { sourceMessage: userMessageRecord },
105→      )
106→      .collect<[Array<{ id: RecordId<"task", string>; title: string; priority?: string }>]>();
107→
108→    expect(taskRows.length).toBeGreaterThan(0);
109→    const task = taskRows[0];
110→    if (!task) {
111→      throw new Error("Task record was not persisted");
112→    }
113→
114→    expect(task.priority).toBe("medium");
115→  }, 30_000);
116→
117→  it("extracts low priority from deferred language", async () => {
118→    const { baseUrl, surreal } = getRuntime();
119→
120→    const message = await fetchJson<ChatMessageResponse>(`${baseUrl}/api/chat/messages`, {
121→      method: "POST",
122→      headers: { "Content-Type": "application/json" },
123→      body: JSON.stringify({
124→        clientMessageId: randomUUID(),
125→        workspaceId: workspace.workspaceId,
126→        conversationId: workspace.conversationId,
127→        text: "Nice to have: eventually add CSV export for reports when we get around to it",
128→      }),
129→    });
130→
131→    const events = await collectSseEvents<StreamEvent>(`${baseUrl}${message.streamUrl}`, 15_000);
132→    const extractionEvent = events.find((event) => event.type === "extraction");
133→    expect(extractionEvent).toBeDefined();
134→
135→    const userMessageRecord = new RecordId("message", message.userMessageId);
136→    const [entityRows] = await surreal
137→      .query<[Array<{ id: RecordId; title?: string; name?: string; priority?: string }>]>(
138→        [
139→          "SELECT id, title, priority FROM task WHERE source_message = $sourceMessage",
140→          "UNION",
141→          "SELECT id, name AS title, priority FROM feature WHERE source_message = $sourceMessage;",
142→        ].join(" "),
143→        { sourceMessage: userMessageRecord },
144→      )
145→      .collect<[Array<{ id: RecordId; title?: string; name?: string; priority?: string }>]>();
146→
147→    expect(entityRows.length).toBeGreaterThan(0);
148→    const entity = entityRows[0];
149→    if (!entity) {
150→      throw new Error("Entity record was not persisted");
151→    }
152→
153→    expect(entity.priority).toBe("low");
154→  }, 30_000);
155→});
