 11→export function createDeterministicIdGenerator(seed: string): () => string {
 12→  let counter = 0;
 13→  return () => {
 14→    const hash = createHash("sha256").update(`${seed}:${counter++}`).digest("hex");
 15→    return `${hash.slice(0, 8)}-${hash.slice(8, 12)}-${hash.slice(12, 16)}-${hash.slice(16, 20)}-${hash.slice(20, 32)}`;
 16→  };
 17→}
 18→
 19→export type EvalRuntime = {
 20→  surreal: Surreal;
 21→  extractionModel: any;
 22→  embeddingModel: any;
 23→  assistantModel: any;
 24→  config: ServerConfig;
 25→  namespace: string;
 26→  database: string;
 27→};
 28→
 29→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 30→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 31→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 32→const schemaPath = join(process.cwd(), "schema", "surreal-schema.surql");
 33→
 34→export async function setupEvalRuntime(suiteName: string): Promise<EvalRuntime> {
 35→  const namespace = `eval_${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 36→  const database = `${suiteName}_${Math.floor(Math.random() * 100000)}`;
 37→
 38→  const surreal = new Surreal();
 39→  await surreal.connect(surrealUrl);
 40→  await surreal.signin({ username: surrealUsername, password: surrealPassword });
 41→
 42→  await surreal.query(`DEFINE NAMESPACE ${namespace};`).catch((error) => {
 43→    if (!isAlreadyExistsError(error)) throw error;
 44→  });
 45→  await surreal.use({ namespace, database });
 46→  await surreal.query(`REMOVE DATABASE ${database};`).catch(() => undefined);
 47→  await surreal.query(`DEFINE DATABASE ${database};`).catch((error) => {
 48→    if (!isAlreadyExistsError(error)) throw error;
 49→  });
 50→  await surreal.use({ namespace, database });
 51→
 52→  const schemaSql = readFileSync(schemaPath, "utf8");
 53→  await surreal.query(schemaSql).catch((error) => {
 54→    if (!isAlreadyExistsError(error)) throw error;
 55→  });
 56→
 57→  const openRouterApiKey = requireEnv("OPENROUTER_API_KEY");
 58→  const extractionModelId = requireEnv("EXTRACTION_MODEL");
 59→  const assistantModelId = requireEnv("ASSISTANT_MODEL");
 60→  const embeddingModelId = requireEnv("OPENROUTER_EMBEDDING_MODEL");
 61→  const embeddingDimension = Number(requireEnv("EMBEDDING_DIMENSION"));
 62→  const extractionStoreThreshold = Number(process.env.EXTRACTION_STORE_THRESHOLD ?? "0.3");
 63→  const extractionDisplayThreshold = Number(process.env.EXTRACTION_DISPLAY_THRESHOLD ?? "0.5");
 64→
 65→  const openrouter = createOpenRouter({ apiKey: openRouterApiKey });
 66→  const extractionModel = openrouter(extractionModelId, { plugins: [{ id: "response-healing" }] });
 67→  const assistantModel = openrouter(assistantModelId, { plugins: [{ id: "response-healing" }] });
 68→  const embeddingModel = openrouter.textEmbeddingModel(embeddingModelId);
 69→
