265→function buildSeedEntityContent(kind: string, text: string, now: Date): Record<string, unknown> {
266→  const base = { created_at: now, updated_at: now };
267→  if (kind === "project") return { ...base, name: text, status: "active" };
268→  if (kind === "feature") return { ...base, name: text, status: "active" };
269→  if (kind === "task") return { ...base, title: text, status: "open" };
270→  if (kind === "decision") return { ...base, summary: text, status: "extracted" };
271→  return { ...base, text, status: "open" };
272→}
