274→export function createEventCollector(): SseRegistry & { getEvents(messageId: string): StreamEvent[] } {
275→  const events = new Map<string, StreamEvent[]>();
276→  return {
277→    registerMessage(messageId: string) {
278→      events.set(messageId, []);
279→    },
280→    handleStreamRequest(_messageId: string): Response {
281→      throw new Error("handleStreamRequest not available in eval mode");
282→    },
283→    emitEvent(messageId: string, event: StreamEvent) {
284→      events.get(messageId)?.push(event);
285→    },
286→    getEvents(messageId: string): StreamEvent[] {
287→      return events.get(messageId) ?? [];
288→    },
289→  };
290→}
