 75→async function runCase(testCase: SuggestionGoldenCase): Promise<SuggestionsEvalOutput> {
 76→  const cacheKey = buildCaseCacheKey(assistantModel, testCase);
 77→  const cached = resultCache[cacheKey];
 78→  if (cached) {
 79→    return cached;
 80→  }
 81→
 82→  const { workspaceRecord, conversationRecord } = await seedWorkspace(runtime.surreal);
 83→  const userMessageRecord = await seedUserMessage(runtime.surreal, conversationRecord, testCase.input);
 84→  const messageId = randomUUID();
 85→
 86→  await runtime.surreal.query(
 87→    "UPDATE $workspace SET onboarding_turn_count += 1, updated_at = $now;",
 88→    { workspace: workspaceRecord, now: new Date() },
 89→  );
 90→
 91→  const sseStub = createEventCollector();
 92→  sseStub.registerMessage(messageId);
 93→
 94→  const deps: ServerDependencies = {
 95→    config: runtime.config,
 96→    surreal: runtime.surreal,
 97→    assistantModel: runtime.assistantModel,
 98→    extractionModel: runtime.extractionModel,
 99→    embeddingModel: runtime.embeddingModel,
100→    sse: sseStub,
101→  };
102→
103→  await processChatMessage({
104→    deps,
105→    conversationId: conversationRecord.id as string,
106→    messageId,
107→    workspaceRecord,
108→    userMessageRecord,
109→    userText: testCase.input,
110→  });
111→
112→  const events = sseStub.getEvents(messageId);
113→  const assistantEvent = events.find((e) => e.type === "assistant_message") as
114→    | { type: "assistant_message"; text: string; suggestions?: string[] }
115→    | undefined;
116→
117→  if (!assistantEvent) {
118→    const errorEvent = events.find((e) => e.type === "error") as
119→      | { type: "error"; error: string }
120→      | undefined;
121→    throw new Error(
122→      `No assistant_message event for case ${testCase.id}; ` +
123→      `events: ${events.map((e) => e.type).join(", ")}` +
124→      (errorEvent ? `; error: ${errorEvent.error}` : ""),
125→    );
126→  }
127→
128→  const output: SuggestionsEvalOutput = {
129→    caseId: testCase.id,
130→    input: testCase.input,
131→    assistantText: assistantEvent.text,
132→    suggestions: assistantEvent.suggestions ?? [],
133→  };
134→
135→  resultCache[cacheKey] = output;
136→  saveCache(cachePath, resultCache);
137→  return output;
138→}
