 2→
 3→function normalize(value: string): string {
 4→  return value
 5→    .toLowerCase()
 6→    .replace(/[^a-z0-9\s]/g, " ")
 7→    .replace(/\s+/g, " ")
 8→    .trim();
 9→}
10→
11→function tokenize(value: string): string[] {
12→  return normalize(value)
13→    .split(" ")
14→    .filter((token) => token.length > 0);
15→}
16→
17→export function nameSimilarity(a: string, b: string): number {
18→  const normalizedA = normalize(a);
19→  const normalizedB = normalize(b);
20→  const aTokens = new Set(tokenize(normalizedA));
21→  const bTokens = new Set(tokenize(normalizedB));
22→
23→  if (normalizedA.length === 0 || normalizedB.length === 0 || aTokens.size === 0 || bTokens.size === 0) {
24→    return 0;
25→  }
26→
27→  const overlap = [...aTokens].filter((token) => bTokens.has(token)).length;
28→  const minSize = Math.min(aTokens.size, bTokens.size);
29→  const union = new Set([...aTokens, ...bTokens]).size;
30→  const jaccard = overlap / union;
31→  const overlapRatio = overlap / minSize;
32→  const substringBonus = normalizedA.includes(normalizedB) || normalizedB.includes(normalizedA) ? 0.2 : 0;
33→  const exactBonus = normalizedA === normalizedB ? 0.2 : 0;
34→
35→  return Math.min(1, Math.max(jaccard, overlapRatio * 0.85) + substringBonus + exactBonus);
36→}
37→
38→export function isEntityNameMatch(a: string, b: string, threshold = 0.5): boolean {
39→  return nameSimilarity(a, b) >= threshold;
40→}
41→
42→export function normalizeForSubstring(value: string): string {
43→  return normalize(value);
44→}
45→
46→export function matchesExpectedEntity(
47→  expectedEntity: ExpectedEntity,
48→  extractedEntity: { kind: string; text: string },
49→  threshold = 0.5,
50→): boolean {
51→  if (expectedEntity.kind !== extractedEntity.kind) {
52→    return false;
53→  }
54→
55→  if ("text_contains" in expectedEntity) {
56→    const expectedSubstring = normalizeForSubstring(expectedEntity.text_contains);
57→    if (expectedSubstring.length === 0) {
58→      return false;
59→    }
60→
61→    return normalizeForSubstring(extractedEntity.text).includes(expectedSubstring);
62→  }
63→
64→  return isEntityNameMatch(expectedEntity.text, extractedEntity.text, threshold);
65→}
